}

let schoolId = event.school_id || event.classId || "UNKNOWN";
let schoolName = event.school_name || event.classId || "Unnamed School";
let binId = event.bin_id || schoolId + "_bin";
let binName = event.bin_name || "Default Bin";
let depositValue = event.deposit_value || 0.15;
let count = event.count || 1;
let timestamp = event.timestamp || new Date().toISOString();
let county = event.county || "School";

node.warn("Processing " + event.item_name + " for " + schoolName);

let recentEvents = flow.get("recentEvents") || {};
let eventKey = schoolId + "_" + binId + "_" + event.barcode + "_" + depositValue;
let nowMs = Date.now();

if (recentEvents[eventKey] && (nowMs - recentEvents[eventKey] < 3000)) {
    return null;
}

recentEvents[eventKey] = nowMs;
flow.set("recentEvents", recentEvents);

if (!data.schools[schoolId]) {
    data.schools[schoolId] = {
        school_id: schoolId,
        school_name: schoolName,
        county: county,
        total_value: 0,
        total_items: 0,
        count_15c: 0,
        count_25c: 0,
        bins: {}
    };
}

let school = data.schools[schoolId];
school.school_name = schoolName;
school.county = county;

if (!school.bins[binId]) {
    school.bins[binId] = {
        bin_id: binId,
        bin_name: binName,
        total_value: 0,
        total_items: 0,
        count_15c: 0,
        count_25c: 0,
        last_updated: null
    };
}

let bin = school.bins[binId];
bin.bin_name = binName;

let addedValue = depositValue * count;
bin.total_value += addedValue;
bin.total_items += count;
bin.last_updated = timestamp;

if (depositValue === 0.15) {
    bin.count_15c += count;
} else {
    bin.count_25c += count;
}

school.total_value += addedValue;
school.total_items += count;

if (depositValue === 0.15) {
    school.count_15c += count;
} else {
    school.count_25c += count;
}

