        count_25c: school.count_25c
    }
};

return msg;

let data = flow.get("leaderboardData") || { schools: {} };

let schoolLeaderboard = [];
let binLeaderboard = [];

for (let schoolId in data.schools) {
    let school = data.schools[schoolId];
    let binCount = Object.keys(school.bins).length;

    schoolLeaderboard.push({
        school_id: school.school_id,
        school_name: school.school_name,
        total_value: Number(school.total_value.toFixed(2)),
        total_items: school.total_items,
        count_15c: school.count_15c,
        count_25c: school.count_25c,
        bin_count: binCount,
        average_per_bin: binCount > 0 ? Number((school.total_value / binCount).toFixed(2)) : 0
    });

    for (let binId in school.bins) {
        let bin = school.bins[binId];
        binLeaderboard.push({
            school_id: school.school_id,
            school_name: school.school_name,
            bin_id: bin.bin_id,
            bin_name: bin.bin_name,
            total_value: Number(bin.total_value.toFixed(2)),
            total_items: bin.total_items,
            count_15c: bin.count_15c,
            count_25c: bin.count_25c,
            last_updated: bin.last_updated
        });
    }
}

schoolLeaderboard.sort((a, b) => b.total_value - a.total_value);
binLeaderboard.sort((a, b) => b.total_value - a.total_value);

schoolLeaderboard = schoolLeaderboard.map((item, index) => ({
    rank: index + 1,
    ...item
}));

binLeaderboard = binLeaderboard.map((item, index) => ({
    rank: index + 1,
    ...item
}));

let totalNationwideValue = schoolLeaderboard.reduce((sum, s) => sum + s.total_value, 0);
let totalNationwideItems = schoolLeaderboard.reduce((sum, s) => sum + s.total_items, 0);

msg.payload = {
    summary: {
        total_schools: schoolLeaderboard.length,
        total_bins: binLeaderboard.length,
        total_nationwide_value: Number(totalNationwideValue.toFixed(2)),
        total_nationwide_items: totalNationwideItems
    },
    school_leaderboard: schoolLeaderboard,
    bin_leaderboard: binLeaderboard
};

return msg;

