function getMl(quantity) {
    if (!quantity) return null;
    const volMatch = quantity.toLowerCase().match(/(\d[\d.]*)\s*(ml|l)/);
    if (!volMatch) return null;
    const value = parseFloat(volMatch[1]);
    return volMatch[2] === 'l' ? value * 1000 : value;
}

const ml = getMl(p.quantity);
let eligibilityStatus = null;

if (p.product_name || msg.barcode || p.code) {
    const isEligible = reTurnApi?.is_eligible === true
        || reTurnApi?.barcodeValid === true
        || (reTurnApi?.is_eligible !== false && reTurnApi?.barcodeValid !== false && ml !== null);
    eligibilityStatus = isEligible ? "YES" : "NO";
}

function calculateDeposit(status, volume) {
    if (status !== "YES" || !volume) return null;
    if (volume >= 150 && volume <= 500) return 0.15;
    if (volume > 500 && volume <= 3000) return 0.25;
    return null;
}

function getAvgPrice(items) {
    const prices = (items || []).filter(function (i) { return typeof i.price === 'number'; });
    if (!prices.length) return null;
    return (prices.reduce(function (sum, i) { return sum + i.price; }, 0) / prices.length).toFixed(2);
}

