function getJSON(url) {
    return new Promise(function (resolve) {
        https.get(url, function (res) {
            var data = '';
            res.on('data', function (chunk) { data += chunk; });
            res.on('end', function () {
                try { resolve(JSON.parse(data)); }
                catch (e) { resolve({}); }
            });
        }).on('error', function () { resolve({}); });
    });
}

