(async () => {
    try {
        const [foodData, priceData, returnData] = await Promise.all([
            getJSON('https://world.openfoodfacts.org/api/v2/product/' + barcode),
            getJSON('https://prices.openfoodfacts.org/api/v1/prices?product_code=' + barcode),
            getJSON('https://re-turn.shanehastings.ie/api/?barcode_number=' + barcode)
        ]);

        const isPartOfScheme = !!(
            returnData?.barcodeValid === true ||
            returnData?.eanValid === true ||
            returnData?.valid === true ||
            returnData?.is_valid === true ||
            returnData?.success === true ||
            returnData?.exists === true ||
            returnData?.status === 200 ||
            returnData?.barcode ||
            (returnData?.message && returnData.message.includes("part of")) ||
            (returnData?.htmlMessage && returnData.htmlMessage.includes("part of")) ||
            returnData?.deposit_value ||
            returnData?.depositValue ||
            (returnData?.bottle && returnData.bottle.deposit)
        );

        if (!isPartOfScheme) {
            return;
        }

        let depositValue = 0.15;
        if (returnData?.htmlMessage?.includes("25c")) {
            depositValue = 0.25;
        } else if (returnData?.deposit_value) {
            depositValue = parseFloat(returnData.deposit_value);
        } else if (returnData?.depositValue) {
            depositValue = parseFloat(returnData.depositValue);
        }

        const product = foodData?.product || {};
        let productName = product.product_name || product.product_name_ro || "";
        let containerType = product.packaging_shapes_tags?.[0]?.replace('en:', '') || "";
        let sizeMl = null;

        if (product.quantity) {
            const match = product.quantity.toLowerCase().match(/(\d[\d.]*)\s*(ml|l)/);
            if (match) {
                sizeMl = match[2] === 'l' ? parseFloat(match[1]) * 1000 : parseFloat(match[1]);
            }
        }

        const enrichedEvent = {
            school_id: eventData.school_id,
            school_name: eventData.school_name,
            bin_id: eventData.bin_id,
            bin_name: eventData.bin_name,
            barcode: barcode,
            item_name: productName,
            container_type: containerType,
            size_ml: sizeMl,
            deposit_value: depositValue,
            count: 1,
            timestamp: new Date().toISOString(),
            county: eventData.county || "Unknown"
        };

        msg.payload = enrichedEvent;
        node.send(msg);

    } catch (error) {
        // silent fail
    }
})();

